```class Solution {
public:
    int minimumChanges(string s, int k) {
        int n = s.size();
        int res = INT_MAX;
        for (int d = 1; d < n; d++) {
            int changes = 0;
            for (int i = 0; i < n; i += d) {
                string t = s.substr(i, d);
                changes += (t != reverse(t).substr(0, t.size()));
            }
            res = min(res, changes);
        }
        return res;
    }
};
